(1, 5, 1, 'words', 'daily_life', 'חלקי גוף', '{"words":[{"english":"Head","hebrew":"ראש","emoji":"🗣️"},{"english":"Hand","hebrew":"יד","emoji":"✋"},{"english":"Foot","hebrew":"רגל","emoji":"🦶"},{"english":"Eye","hebrew":"עין","emoji":"👁️"},{"english":"Ear","hebrew":"אוזן","emoji":"👂"}]}'::jsonb, 60, 15),

(1, 5, 2, 'words', 'football', 'פעולות במגרש', '{"words":[{"english":"Shoot","hebrew":"בעט","emoji":"🦵"},{"english":"Jump","hebrew":"קפוץ","emoji":"🤸"},{"english":"Catch","hebrew":"תפוס","emoji":"🧤"},{"english":"Throw","hebrew":"זרוק","emoji":"🤾"},{"english":"Score","hebrew":"הבקע","emoji":"🥅"}]}'::jsonb, 60, 15),

(1, 5, 3, 'quiz', 'daily_life', 'חידון גוף ופעולות', '{"questions":[{"question":"What do you kick the ball with?","options":["Hand","Foot","Head","Ear"],"correct":1,"emoji":"⚽","explanation_he":"Foot = רגל, בועטים בכדור עם הרגל!"},{"question":"What do you see with?","options":["Ear","Hand","Eye","Foot"],"correct":2,"emoji":"👀","explanation_he":"Eye = עין, רואים עם העיניים!"},{"question":"What does the goalkeeper do?","options":["Shoot","Score","Catch","Jump"],"correct":2,"emoji":"🧤","explanation_he":"Catch = תפוס, השוער תופס את הכדור!"},{"question":"How do you say קפוץ in English?","options":["Run","Jump","Throw","Kick"],"correct":1,"emoji":"🤸","explanation_he":"Jump = קפוץ!"},{"question":"What do you hear with?","options":["Eye","Ear","Hand","Head"],"correct":1,"emoji":"👂","explanation_he":"Ear = אוזן, שומעים עם האוזניים!"}],"timer_seconds":20,"speed_bonus":true}'::jsonb, 80, 20),

(1, 5, 4, 'conversation', 'football', 'אימון עם המאמן', '{"dialogue":[{"speaker":"coach","text":"Are you ready to train?","hebrew":"אתה מוכן להתאמן?","emoji":"💪"},{"speaker":"child","hebrew":"תגיד לו שכן!","options":["Yes, I am ready!","No, thank you","Maybe later"],"correct":0},{"speaker":"coach","text":"Great! Kick the ball!","hebrew":"מעולה! בעט בכדור!","emoji":"⚽"},{"speaker":"child","hebrew":"ספר לו שבעטת חזק!","options":["I kicked it hard!","I dont know","What ball?"],"correct":0},{"speaker":"coach","text":"Amazing shot! You scored a goal!","hebrew":"בעיטה מדהימה! הבקעת שער!","emoji":"🥅"},{"speaker":"child","hebrew":"תודה למאמן!","options":["Thank you, coach!","OK bye","I want to go home"],"correct":0}]}'::jsonb, 80, 20),

