(1, 6, 3, 'quiz', 'daily_life', 'חידון אוכל ואותיות', '{"questions":[{"question":"How do you say מים in English?","options":["Milk","Water","Juice","Tea"],"correct":1,"emoji":"💧","explanation_he":"Water = מים, חשוב לשתות מים!"},{"question":"What letter does Lion start with?","options":["M","K","L","N"],"correct":2,"emoji":"🦁","explanation_he":"Lion מתחיל באות L!"},{"question":"How do you say תפוח?","options":["Banana","Orange","Apple","Bread"],"correct":2,"emoji":"🍎","explanation_he":"Apple = תפוח!"},{"question":"What letter does Maccabi start with?","options":["N","M","K","L"],"correct":1,"emoji":"💛","explanation_he":"Maccabi מתחיל באות M!"},{"question":"How do you say לחם?","options":["Bread","Water","Chicken","Apple"],"correct":0,"emoji":"🍞","explanation_he":"Bread = לחם!"}],"timer_seconds":20,"speed_bonus":true}'::jsonb, 80, 20),

(1, 6, 4, 'conversation', 'daily_life', 'הזמנת אוכל', '{"dialogue":[{"speaker":"coach","text":"Are you hungry?","hebrew":"אתה רעב?","emoji":"😋"},{"speaker":"child","hebrew":"תגיד שכן, אתה רעב!","options":["Yes, I am hungry!","No thanks","I dont know"],"correct":0},{"speaker":"coach","text":"What do you want to eat?","hebrew":"מה אתה רוצה לאכול?","emoji":"🍽️"},{"speaker":"child","hebrew":"תבקש תפוח!","options":["I want an apple, please","I want nothing","Give me everything"],"correct":0},{"speaker":"coach","text":"Here you go! Do you want water too?","hebrew":"הנה! אתה רוצה גם מים?","emoji":"🍎"},{"speaker":"child","hebrew":"תודה ובקש מים!","options":["Yes please, and thank you!","No way","I forgot"],"correct":0}]}'::jsonb, 80, 20),

