(1, 7, 1, 'words', 'daily_life', 'המשפחה שלי', '{"words":[{"english":"Mother","hebrew":"אמא","emoji":"👩"},{"english":"Father","hebrew":"אבא","emoji":"👨"},{"english":"Brother","hebrew":"אח","emoji":"👦"},{"english":"Sister","hebrew":"אחות","emoji":"👧"},{"english":"Family","hebrew":"משפחה","emoji":"👨‍👩‍👧‍👦"}]}'::jsonb, 60, 15),

(1, 7, 2, 'words', 'daily_life', 'רגשות', '{"words":[{"english":"Happy","hebrew":"שמח","emoji":"😊"},{"english":"Sad","hebrew":"עצוב","emoji":"😢"},{"english":"Excited","hebrew":"נרגש","emoji":"🤩"},{"english":"Brave","hebrew":"אמיץ","emoji":"💪"},{"english":"Proud","hebrew":"גאה","emoji":"🏆"}]}'::jsonb, 60, 15),

(1, 7, 3, 'quiz', 'daily_life', 'חידון משפחה ורגשות', '{"questions":[{"question":"How do you say אמא in English?","options":["Father","Brother","Mother","Sister"],"correct":2,"emoji":"👩","explanation_he":"Mother = אמא!"},{"question":"When you win a game, you feel...","options":["Sad","Happy","Scared","Tired"],"correct":1,"emoji":"🏆","explanation_he":"Happy = שמח! כשמנצחים שמחים!"},{"question":"How do you say אח?","options":["Sister","Father","Mother","Brother"],"correct":3,"emoji":"👦","explanation_he":"Brother = אח!"},{"question":"A hero is always...","options":["Sad","Scared","Brave","Tired"],"correct":2,"emoji":"💪","explanation_he":"Brave = אמיץ! גיבורים אמיצים!"},{"question":"How do you say גאה?","options":["Proud","Happy","Excited","Brave"],"correct":0,"emoji":"🏆","explanation_he":"Proud = גאה! תהיה גאה בעצמך!"}],"timer_seconds":20,"speed_bonus":true}'::jsonb, 80, 20),

(1, 7, 4, 'conversation', 'daily_life', 'סיפור על המשפחה', '{"dialogue":[{"speaker":"coach","text":"Tell me about your family!","hebrew":"ספר לי על המשפחה שלך!","emoji":"👨‍👩‍👧‍👦"},{"speaker":"child","hebrew":"ספר על האחים שלך!","options":["I have two brothers!","I dont have family","I forgot"],"correct":0},{"speaker":"coach","text":"Wow, thats great! Are you happy together?","hebrew":"וואו, מדהים! אתם שמחים ביחד?","emoji":"😊"},{"speaker":"child","hebrew":"תגיד שכן!","options":["Yes, we are very happy!","Sometimes","Not really"],"correct":0},{"speaker":"coach","text":"Your family must be proud of you!","hebrew":"המשפחה שלך בטח גאה בך!","emoji":"🏆"},{"speaker":"child","hebrew":"תגיד תודה!","options":["Thank you! I am proud too!","OK","Whatever"],"correct":0}]}'::jsonb, 80, 20),

