(1, 8, 3, 'quiz', 'football', 'חידון סופר על הכל', '{"questions":[{"question":"The best team wins the...","options":["Ball","Stadium","Trophy","Captain"],"correct":2,"emoji":"🏆","explanation_he":"Trophy = גביע! הקבוצה הטובה ביותר מנצחת את הגביע!"},{"question":"David was a brave...","options":["Shepherd","Captain","Coach","Player"],"correct":0,"emoji":"🐑","explanation_he":"Shepherd = רועה! דוד היה רועה צאן אמיץ!"},{"question":"The leader of the team is the...","options":["Trophy","Victory","Stadium","Captain"],"correct":3,"emoji":"©️","explanation_he":"Captain = קפטן! המנהיג של הקבוצה!"},{"question":"Something amazing that happens is a...","options":["Victory","Miracle","Wisdom","Trophy"],"correct":1,"emoji":"✨","explanation_he":"Miracle = נס! כמו הניסים בתנך!"},{"question":"When you win a game, its a...","options":["Stadium","Captain","Trophy","Victory"],"correct":3,"emoji":"🎉","explanation_he":"Victory = ניצחון!"},{"question":"Solomon was known for his...","options":["Victory","Miracle","Wisdom","Trophy"],"correct":2,"emoji":"🧠","explanation_he":"Wisdom = חוכמה! שלמה המלך היה חכם מכל אדם!"}],"timer_seconds":25,"speed_bonus":true}'::jsonb, 100, 30),

(1, 8, 4, 'conversation', 'football', 'ראיון אחרי המשחק', '{"dialogue":[{"speaker":"coach","text":"Congratulations! You played amazing today!","hebrew":"מזל טוב! שיחקת מדהים היום!","emoji":"🎉"},{"speaker":"child","hebrew":"תודה למאמן!","options":["Thank you so much, coach!","OK","It was easy"],"correct":0},{"speaker":"coach","text":"How do you feel after this victory?","hebrew":"איך אתה מרגיש אחרי הניצחון?","emoji":"🏆"},{"speaker":"child","hebrew":"ספר שאתה שמח וגאה!","options":["I feel happy and proud!","I feel nothing","I want to go home"],"correct":0},{"speaker":"coach","text":"You are a true champion! Keep learning!","hebrew":"אתה אלוף אמיתי! תמשיך ללמוד!","emoji":"👑"},{"speaker":"child","hebrew":"תגיד שתמשיך ללמוד!","options":["I will keep learning every day!","Maybe tomorrow","I dont want to"],"correct":0}]}'::jsonb, 100, 30);
